import type { ScaleOrdinal } from 'd3-scale';

import { getColorFromNumericScale } from './get-color-from-numeric-scale.js';
import { SCALE_FALLBACK_COLOR } from '../../../core/constants.js';
import { isNumericColoringScale, isString } from '../../types/guards.js';
import type { XYChartColorScale } from '../../types/xy-chart-internals.js';

export const getColorFromScaleAndData = (
  colorScale: XYChartColorScale,
  value: number | string,
  colorOverride?: string,
): string => {
  if (colorOverride) {
    return colorOverride;
  }

  if (isString(value)) {
    return (colorScale as ScaleOrdinal<string, string>)(value);
  }

  if (isNumericColoringScale(colorScale)) {
    return getColorFromNumericScale(colorScale, value);
  }

  return SCALE_FALLBACK_COLOR;
};
